-- ============================================================================
-- Seed Product Center mock categories and attributes as real Supabase data
-- ============================================================================
-- Source: src/components/admin/product-center/context/mockData.ts
--         buildWebsiteCategories() + buildWebsiteAttributes()
--
-- The original frontend mock ids are text (cat_..., attr_...), while the
-- product center tables use uuid primary keys. These rows use stable md5-based
-- UUIDs and prefix category codes with mock: so they can coexist with the
-- storefront backfill that uses storefront:* codes.

create or replace function public.pc_uuid_from_text(p_input text)
returns uuid
language sql
immutable
as $$
  select (
    substr(md5(coalesce(p_input, '')), 1, 8) || '-' ||
    substr(md5(coalesce(p_input, '')), 9, 4) || '-' ||
    substr(md5(coalesce(p_input, '')), 13, 4) || '-' ||
    substr(md5(coalesce(p_input, '')), 17, 4) || '-' ||
    substr(md5(coalesce(p_input, '')), 21, 12)
  )::uuid;
$$;

alter table public.pc_product_categories
  drop constraint if exists pc_product_categories_level_check;

alter table public.pc_product_categories
  add constraint pc_product_categories_level_check
  check (level between 1 and 12);

