insert into public.pc_product_categories (
  id, tenant_id, parent_id, level, code, name, name_en, sort_order,
  seo_title, seo_description, is_active
)
select
  id, tenant_id, parent_id, level, code, name, name_en, sort_order,
  seo_title, seo_description, is_active
from seed_categories
on conflict (tenant_id, code) do update set
  parent_id = excluded.parent_id,
  level = excluded.level,
  name = excluded.name,
  name_en = excluded.name_en,
  sort_order = excluded.sort_order,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  is_active = excluded.is_active,
  updated_at = now();

with seed_attributes (
  id, tenant_id, code, label, data_type, unit, is_filterable, options,
  applies_to_category_ids, sort_order
